'use client';

const teamMembers = [
    "M ABHINAV",
    "R VINAY KUMAR",
    "M NIHARIKA",
    "M SAI HANSIKA",
    "G PUNEETH"
];

export default function TeamPage() {
    return (
        <div className="max-w-7xl mx-auto px-4 py-24">
            <div className="text-center mb-20 max-w-2xl mx-auto">
                <h1 className="text-4xl font-extrabold text-slate-900 mb-4 tracking-tight">Our Dedicated Team</h1>
                <p className="text-lg text-slate-500 leading-relaxed">
                    The innovative minds from <span className="text-indigo-600 font-bold">Kalasalingam Academy of Research and Education</span> driving the future of legal tech.
                </p>
                <div className="w-24 h-1.5 bg-indigo-600 mx-auto mt-8 rounded-full"></div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-8">
                {teamMembers.map((name, idx) => (
                    <div
                        key={name}
                        className="group relative bg-white p-8 rounded-2xl shadow-sm border border-slate-100 hover:shadow-xl hover:-translate-y-1 transition duration-300 text-center"
                    >
                        <div className="relative mb-6">
                            <div className="w-24 h-24 bg-indigo-50 rounded-2xl mx-auto flex items-center justify-center text-indigo-600 font-black text-3xl group-hover:bg-indigo-600 group-hover:text-white transition duration-300 rotate-3 group-hover:rotate-0">
                                {name.charAt(0)}
                            </div>
                            <div className="absolute -bottom-2 -right-1 bg-amber-400 text-white w-8 h-8 rounded-full border-4 border-white flex items-center justify-center font-bold text-xs ring-1 ring-slate-100 italic">
                                {idx + 1}
                            </div>
                        </div>

                        <h3 className="text-lg font-black text-slate-900 mb-1">{name}</h3>
                        <p className="text-indigo-600 text-xs font-bold uppercase tracking-widest">Research Scholar</p>

                        <div className="mt-6 flex justify-center gap-3 opacity-0 group-hover:opacity-100 transition duration-300">
                            <div className="w-8 h-8 bg-slate-50 rounded-full border border-slate-200"></div>
                            <div className="w-8 h-8 bg-slate-50 rounded-full border border-slate-200"></div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="mt-32 p-12 bg-indigo-600 rounded-3xl text-center text-white relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full -mr-32 -mt-32 blur-3xl"></div>
                <h2 className="text-3xl font-bold mb-4">Interested in our research?</h2>
                <p className="text-indigo-100 max-w-xl mx-auto mb-8">
                    Contact our academy for collaborative opportunities in AI-driven legal systems.
                </p>
                <button className="px-8 py-3 bg-white text-indigo-600 rounded-xl font-bold hover:bg-slate-50 transition">
                    Contact Dept
                </button>
            </div>
        </div>
    );
}
